                del target_parent[int(target_key)]
            else:
                del target_parent[target_key]

        elif op == 'replace':
            if path == '':
                result = value
            elif isinstance(target_parent, list):
                target_parent[int(target_key)] = value
            else:
                target_parent[target_key] = value

    return result
